import SequelizeAdapter from "../database/sequelize-adapter-src";
import sequelize from "../database/sequelize";
import db from "../database/db";
import {
  userAttributes,
  userInclude,
} from "../database/models/attributesAndIncludes";
import {
  wechatFakeEmailDomain,
  ssoFakeEmailDomain,
  email2UnionId,
  email2SsoUserId,
} from "./fakeEmail";
import { checkAndComputeUserFields } from "api/routes/checkAndComputeUserFields";

export const adapter = {
  ...SequelizeAdapter(sequelize, {
    // `as any` is because SequelizeAdapter requires user.email to be
    // non-nullable
    models: { User: db.User as any },
  }),

  // We use custom `createUser` logic because we process sign-ups differently
  // depending on the fake email domain. For WeChat, we only care about
  // `wechatUnionId`.
  // For SSO, we create the user with `ssoUserId` along with their standard
  // profile.
  async createUser(user: {
    email: string;
    realEmail?: string;
    phone?: string;
    name?: string;
  }) {
    // Pass everything inside a transaction to ensure rollback on failure
    return await sequelize.transaction(async (transaction) => {
      return await adapter.createUserImpl(user, transaction);
    });
  },

  async createUserImpl(
    user: {
      email: string;
      realEmail?: string;
      phone?: string;
      name?: string;
    },
    transaction: any
  ) {
    if (user.email.endsWith(wechatFakeEmailDomain)) {
      const wechatUnionId = email2UnionId(user.email);
      console.log("adapter.createUser(wechat):", wechatUnionId);
      return await db.User.create({ wechatUnionId }, { transaction });
    } else if (user.email.endsWith(ssoFakeEmailDomain)) {
      const ssoUserId = email2SsoUserId(user.email);
      console.log("adapter.createUser(sso):", ssoUserId);
      const fields = await checkAndComputeUserFields({
        email: user.realEmail || undefined,
        name: user.name || undefined,
        isVolunteer: false,
        oldUrl: null,
        transaction,
      });
      return await db.User.create(
        {
          ...fields,
          ssoUserId,
          phone: user.phone || null,
        },
        { transaction }
      );
    } else {
      throw new Error(`Invalid email domain for creation: ${user.email}`);
    }
  },

  async getUserByEmail(email: string) {
    return await adapter.getUserByEmailImpl(email);
  },

  async getUserByEmailImpl(email: string, transaction?: any) {
    if (email.endsWith(wechatFakeEmailDomain)) {
      const wechatUnionId = email2UnionId(email);
      console.log(`adapter.getUserByEmail(wechat): ${wechatUnionId}`);
      return await db.User.findOne({
        where: { wechatUnionId },
        attributes: userAttributes,
        include: userInclude,
        transaction,
      });
    } else if (email.endsWith(ssoFakeEmailDomain)) {
      const ssoUserId = email2SsoUserId(email);
      console.log(`adapter.getUserByEmail(sso): ${ssoUserId}`);
      return await db.User.findOne({
        where: { ssoUserId },
        attributes: userAttributes,
        include: userInclude,
        transaction,
      });
    }
    return null;
  },
};

/**
 * <div style={{display: "flex", justifyContent: "space-between", alignItems: "center", padding: 16}}>
 *  <p style={{fontWeight: "normal"}}>Official <a href="https://sequelize.org/docs/v6/getting-started/">Sequilize</a> adapter for Auth.js / NextAuth.js.</p>
 *  <a href="https://sequelize.org/">
 *   <img style={{display: "block"}} src="https://authjs.dev/img/adapters/sequelize.svg" height="30"/>
 *  </a>
 * </div>
 *
 * ## Installation
 *
 * ```bash npm2yarn2pnpm
 * npm install next-auth @auth/sequelize-adapter sequelize
 * ```
 *
 * @module @auth/sequelize-adapter
 */
import type {
  Adapter,
  AdapterUser,
  AdapterAccount,
  AdapterSession,
  VerificationToken,
} from "@auth/core/adapters"
import { Sequelize, Model, ModelCtor } from "sequelize"
import * as defaultModels from "./models.js"

export { defaultModels as models }

// @see https://sequelize.org/master/manual/typescript.html
//@ts-expect-error
interface AccountInstance
  extends Model<AdapterAccount, Partial<AdapterAccount>>,
    AdapterAccount {}
interface UserInstance
  extends Model<AdapterUser, Partial<AdapterUser>>,
    AdapterUser {}
interface SessionInstance
  extends Model<AdapterSession, Partial<AdapterSession>>,
    AdapterSession {}
interface VerificationTokenInstance
  extends Model<VerificationToken, Partial<VerificationToken>>,
    VerificationToken {}

/** This is the interface of the Sequelize adapter options. */
export interface SequelizeAdapterOptions {
  /**
   * Whether to {@link https://sequelize.org/docs/v6/core-concepts/model-basics/#model-synchronization synchronize} the models or not.
   */
  synchronize?: boolean
  /**
   * The {@link https://sequelize.org/docs/v6/core-concepts/model-basics/ Sequelize Models} related to Auth.js that will be created in your database.
   */
  models?: Partial<{
    User: ModelCtor<UserInstance>
    Account: ModelCtor<AccountInstance>
    Session: ModelCtor<SessionInstance>
    VerificationToken: ModelCtor<VerificationTokenInstance>
  }>
}

/**
 * :::warning
 * You'll also have to manually install [the driver for your database](https://sequelize.org/master/manual/getting-started.html) of choice.
 * :::
 *
 * ## Setup
 *
 * ### Configuring Auth.js
 *
 *  Add this adapter to your `pages/api/[...nextauth].js` next-auth configuration object.
 *
 * ```javascript title="pages/api/auth/[...nextauth].js"
 * import NextAuth from "next-auth"
 * import SequelizeAdapter from "@auth/sequelize-adapter"
 * import { Sequelize } from "sequelize"
 *
 * // https://sequelize.org/master/manual/getting-started.html#connecting-to-a-database
 * const sequelize = new Sequelize("yourconnectionstring")
 *
 * // For more information on each option (and a full list of options) go to
 * // https://authjs.dev/reference/configuration/auth-config
 * export default NextAuth({
 *   // https://authjs.dev/reference/providers/
 *   providers: [],
 *   adapter: SequelizeAdapter(sequelize),
 * })
 * ```
 *
 * ### Updating the database schema
 *
 * By default, the sequelize adapter will not create tables in your database. In production, best practice is to create the [required tables](https://authjs.dev/reference/adapters/models) in your database via [migrations](https://sequelize.org/master/manual/migrations.html). In development, you are able to call [`sequelize.sync()`](https://sequelize.org/master/manual/model-basics.html#model-synchronization) to have sequelize create the necessary tables, foreign keys and indexes:
 *
 * > This schema is adapted for use in Sequelize and based upon our main [schema](https://authjs.dev/reference/adapters#models)
 *
 * ```js
 * import NextAuth from "next-auth"
 * import SequelizeAdapter from "@auth/sequelize-adapter"
 * import Sequelize from 'sequelize'
 *
 * const sequelize = new Sequelize("sqlite::memory:")
 * const adapter = SequelizeAdapter(sequelize)
 *
 * // Calling sync() is not recommended in production
 * sequelize.sync()
 *
 * export default NextAuth({
 *   ...
 *   adapter
 *   ...
 * })
 * ```
 *
 * ## Advanced usage
 *
 * ### Using custom models
 *
 * Sequelize models are option to customization like so:
 *
 * ```js
 * import NextAuth from "next-auth"
 * import SequelizeAdapter, { models } from "@auth/sequelize-adapter"
 * import Sequelize, { DataTypes } from "sequelize"
 *
 * const sequelize = new Sequelize("sqlite::memory:")
 *
 * export default NextAuth({
 *   // https://authjs.dev/reference/providers/
 *   providers: [],
 *   adapter: SequelizeAdapter(sequelize, {
 *     models: {
 *       User: sequelize.define("user", {
 *         ...models.User,
 *         phoneNumber: DataTypes.STRING,
 *       }),
 *     },
 *   }),
 * })
 * ```
 */
export default function SequelizeAdapter(
  client: Sequelize,
  options?: SequelizeAdapterOptions
): Adapter {
  const { models, synchronize = true } = options ?? {}
  const defaultModelOptions = { underscored: true, timestamps: false }
  const { User, Account, Session, VerificationToken } = {
    User:
      models?.User ??
      client.define<UserInstance>(
        "user",
        defaultModels.User,
        defaultModelOptions
      ),
    Account:
      models?.Account ??
      client.define<AccountInstance>(
        "account",
        defaultModels.Account,
        defaultModelOptions
      ),
    Session:
      models?.Session ??
      client.define<SessionInstance>(
        "session",
        defaultModels.Session,
        defaultModelOptions
      ),
    VerificationToken:
      models?.VerificationToken ??
      client.define<VerificationTokenInstance>(
        "verificationToken",
        defaultModels.VerificationToken,
        defaultModelOptions
      ),
  }
  let _synced = false
  const sync = async () => {
    if (process.env.NODE_ENV !== "production" && synchronize && !_synced) {
      const syncOptions =
        typeof synchronize === "object" ? synchronize : undefined

      await Promise.all([
        User.sync(syncOptions),
        Account.sync(syncOptions),
        Session.sync(syncOptions),
        VerificationToken.sync(syncOptions),
      ])

      _synced = true
    }
  }

  Account.belongsTo(User, { onDelete: "cascade" })
  Session.belongsTo(User, { onDelete: "cascade" })

  return {
    async createUser(user) {
      console.log(">>> createUser", user)
      await sync()

      return await User.create(user)
    },
    async getUser(id) {
      await sync()

      const userInstance = await User.findByPk(id)

      return userInstance?.get({ plain: true }) ?? null
    },
    async getUserByEmail(email) {
      await sync()

      const userInstance = await User.findOne({
        where: { email },
      })

      return userInstance?.get({ plain: true }) ?? null
    },
    async getUserByAccount({ provider, providerAccountId }) {
      await sync()

      const accountInstance = await Account.findOne({
        // @ts-expect-error
        where: { provider, providerAccountId },
      })

      if (!accountInstance) {
        return null
      }

      const userInstance = await User.findByPk(accountInstance.userId)

      return userInstance?.get({ plain: true }) ?? null
    },
    async updateUser(user) {
      await sync()

      await User.update(user, { where: { id: user.id } })
      const userInstance = await User.findByPk(user.id)

      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
      return userInstance!
    },
    async deleteUser(userId) {
      await sync()

      const userInstance = await User.findByPk(userId)

      await User.destroy({ where: { id: userId } })

      return userInstance
    },
    async linkAccount(account) {
      await sync()

      await Account.create(account)
    },
    async unlinkAccount({ provider, providerAccountId }) {
      await sync()

      await Account.destroy({
        where: { provider, providerAccountId },
      })
    },
    async createSession(session) {
      await sync()

      return await Session.create(session)
    },
    async getSessionAndUser(sessionToken) {
      await sync()

      const sessionInstance = await Session.findOne({
        where: { sessionToken },
      })

      if (!sessionInstance) {
        return null
      }

      const userInstance = await User.findByPk(sessionInstance.userId)

      if (!userInstance) {
        return null
      }

      return {
        session: sessionInstance?.get({ plain: true }),
        user: userInstance?.get({ plain: true }),
      }
    },
    async updateSession({ sessionToken, expires }) {
      await sync()

      await Session.update(
        { expires, sessionToken },
        { where: { sessionToken } }
      )

      return await Session.findOne({ where: { sessionToken } })
    },
    async deleteSession(sessionToken) {
      await sync()

      const session = await Session.findOne({ where: { sessionToken } })
      await Session.destroy({ where: { sessionToken } })
      return session?.get({ plain: true })
    },
    async createVerificationToken(token) {
      await sync()

      return await VerificationToken.create(token)
    },
    async useVerificationToken({ identifier, token }) {
      await sync()

      const tokenInstance = await VerificationToken.findOne({
        where: { identifier, token },
      })

      await VerificationToken.destroy({ where: { identifier } })

      return tokenInstance?.get({ plain: true }) ?? null
    },
  }
}

import { DataTypes } from "sequelize";
export const Account = {
    id: {
        type: DataTypes.UUID,
        defaultValue: DataTypes.UUIDV4,
        primaryKey: true,
    },
    type: { type: DataTypes.STRING, allowNull: false },
    provider: { type: DataTypes.STRING, allowNull: false },
    providerAccountId: { type: DataTypes.STRING, allowNull: false },
    // OAuth access/refresh tokens are often JWTs or JWEs and exceed 255 chars.
    refresh_token: { type: DataTypes.TEXT },
    access_token: { type: DataTypes.TEXT },
    expires_at: { type: DataTypes.INTEGER },
    token_type: { type: DataTypes.STRING },
    scope: { type: DataTypes.STRING },
    id_token: { type: DataTypes.TEXT },
    session_state: { type: DataTypes.STRING },
    userId: { type: DataTypes.UUID },
};
export const User = {
    id: {
        type: DataTypes.UUID,
        defaultValue: DataTypes.UUIDV4,
        primaryKey: true,
    },
    name: { type: DataTypes.STRING },
    email: { type: DataTypes.STRING, unique: "email" },
    emailVerified: { type: DataTypes.DATE },
    image: { type: DataTypes.STRING },
};
export const Session = {
    id: {
        type: DataTypes.UUID,
        defaultValue: DataTypes.UUIDV4,
        primaryKey: true,
    },
    expires: { type: DataTypes.DATE, allowNull: false },
    sessionToken: {
        type: DataTypes.STRING,
        unique: "sessionToken",
        allowNull: false,
    },
    userId: { type: DataTypes.UUID },
};
export const VerificationToken = {
    token: { type: DataTypes.STRING, primaryKey: true },
    identifier: { type: DataTypes.STRING, allowNull: false },
    expires: { type: DataTypes.DATE, allowNull: false },
};

import { Sequelize } from "sequelize-typescript";
import pg from "pg";
import { hookIsPartialAfterSequelizeInit } from "./modelHelpers/ZodColumn";
import db from "./db";

if (!process.env.DATABASE_URI) {
  throw new Error("DATABASE_URI is not set.");
}

const sequelize = new Sequelize(process.env.DATABASE_URI, {
  models: Object.values(db),
  logging: false,
  dialectModule: pg,

  retry: {
    // Error types: https://sequelize.org/api/v6/identifiers.html#errors
    match: [
      /ConnectionError/, // Fix pg vercel bug: https://github.com/orgs/vercel/discussions/234
    ],
    max: 3,
  },

  pool: {
    max: parseInt(process.env.DATABASE_MAX_POOL_SIZE ?? "5"),
    min: parseInt(process.env.DATABASE_MIN_POOL_SIZE ?? "0"),
  },
});

hookIsPartialAfterSequelizeInit();

export default sequelize;

import sequelize, { ModelAttributeColumnOptions } from "sequelize";

import { addAttribute } from "sequelize-typescript/dist/model/column/attribute-service";
import { getSequelizeTypeByDesignType } from "sequelize-typescript/dist/model/shared/model-service";
import { isDataType } from "sequelize-typescript/dist/sequelize/data-type/data-type-service";
import z, { ZodError, ZodTypeAny } from "zod";
import { Model } from "sequelize-typescript";

type OptionsOrDataType =
  | Partial<ModelAttributeColumnOptions>
  | sequelize.DataType;

export class ZodColumnGetError extends Error {
  constructor(propertyName: string, val: any, zodError: ZodError) {
    const msg = `get ${propertyName} = ${JSON.stringify(val)}, got error ${zodError.toString()}`;
    super(msg);
  }
}

export class ZodColumnSetError extends Error {
  constructor(propertyName: string, val: any, zodError: ZodError) {
    const msg = `set ${propertyName} = ${JSON.stringify(val)}, got error ${zodError.toString()}`;
    super(msg);
  }
}

// from https://github.com/sequelize/sequelize-typescript/blob/master/src/model/column/column.ts
export default function ZodColumn(
  optionsOrDataType: OptionsOrDataType,
  zodType: ZodTypeAny,
) {
  return (
    target: any,
    propertyName: string,
    propertyDescriptor?: PropertyDescriptor,
  ) => {
    annotate(
      optionsOrDataType,
      zodType,
      target,
      propertyName,
      propertyDescriptor ??
        Object.getOwnPropertyDescriptor(target, propertyName),
    );
  };
}

function annotate(
  optionsOrDataType: OptionsOrDataType,
  zodType: ZodTypeAny,
  target: any,
  propertyName: string,
  propertyDescriptor?: PropertyDescriptor,
): void {
  let options: Partial<ModelAttributeColumnOptions>;

  if (isDataType(optionsOrDataType)) {
    options = {
      type: optionsOrDataType,
    };
  } else {
    options = { ...(optionsOrDataType as ModelAttributeColumnOptions) };

    if (!options.type) {
      options.type = getSequelizeTypeByDesignType(target, propertyName);
    }
  }

  const originalGet = propertyDescriptor?.get;
  const originalSet = propertyDescriptor?.set;

  // skip it in production
  if (process.env.NODE_ENV === "production") {
    if (originalGet) options.get = originalGet;
    if (originalSet) options.set = originalSet;
    addAttribute(target, propertyName, options);
    return;
  }

  if (zodType) {
    options.get = function () {
      // console.log('this._options', this._options);
      let finalZodType = zodType;
      // @ts-expect-error
      if (this._options._isPartial) {
        finalZodType = z.optional(zodType);
      }
      const val = this.getDataValue(propertyName); // TODO how to call original property descriptor?
      const parsed = finalZodType.safeParse(val);
      if (parsed.success === true) {
        return parsed.data;
      } else {
        throw new ZodColumnGetError(propertyName, val, parsed.error);
      }
    };
    options.set = function (val: any) {
      const parsed = zodType.safeParse(val);
      if (parsed.success === true) {
        this.setDataValue(propertyName, parsed.data); // TODO how to call original property descriptor?
      } else {
        throw new ZodColumnSetError(propertyName, val, parsed.error);
      }
    };
  } else {
    if (originalGet) options.get = originalGet;
    if (originalSet) options.set = originalSet;
  }

  addAttribute(target, propertyName, options);
}

// Model.update may construct a partial model, causing zod validation failure.
// original code: https://github.com/sequelize/sequelize/blob/main/src/model.js
export const hookIsPartialAfterSequelizeInit = () => {
  const originalUpdate = Model.update;
  // @ts-expect-error
  Model.update = function (values, ...args) {
    // console.log("Model.update", values, ...args);
    // @ts-expect-error
    values._isPartial = true;
    return originalUpdate.call(this, values, ...args);
  };

  const originalBuild = Model.build;
  // @ts-expect-error
  Model.build = function (values, options) {
    // console.log("Model.build", values, options);
    // @ts-expect-error
    if (values._isPartial) {
      // @ts-expect-error
      delete values._isPartial;
      options = options || {};
      // @ts-expect-error
      options._isPartial = true;
    }
    return originalBuild.call(this, values, options);
  };
};

