/**
 * A group is said to be "owned" if the mentorship or interview field is non-null.
 * Otherwise the group is said to be "unowned".
 *
 * TODO: Add an index on `achived`
 */
@Table({
  tableName: "groups",
  modelName: "group",
})
@Fix
class Group extends Model {
  @Unique
  @IsUUID(4)
  @PrimaryKey
  @Default(UUIDV4)
  @Column(UUID)
  id: CreationOptional<string>;

  @Column(STRING)
